using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ── CalculateTotal: DataRow-driven tests ──────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 10, 0.10, 0.00, DisplayName = "Zero unit price")]
    [DataRow(99.99, 0, 0.20, 0.00, DisplayName = "Zero quantity")]
    [DataRow(100.00, 2, 1.0, 400.00, DisplayName = "Maximum tax rate (100%)")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── CalculateTotal: DynamicData-driven tests ──────────────────────

    public static IEnumerable<object[]> LargeOrderData =>
    [
        [1000.00m, 100, 0.05m, 105_000.00m],
        [0.01m, 10_000, 0.0m, 100.00m],
        [49.99m, 250, 0.15m, 14_372.125m],
    ];

    [TestMethod]
    [DynamicData(nameof(LargeOrderData), DynamicDataSourceType.Property)]
    [Description("Validates totals for large-volume orders using decimal-precise inputs")]
    public void CalculateTotal_WithLargeOrders_ReturnsExpected(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    // ── CalculateTotal: invalid input tests ───────────────────────────

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, DisplayName = "Negative unit price")]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity")]
    [DataRow(10.00, 1, -0.01, DisplayName = "Negative tax rate")]
    [DataRow(10.00, 1, 1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_WithInvalidInputs_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    // ── ApplyDiscount: DataRow-driven tests ───────────────────────────

    [TestMethod]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "No discount")]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% discount")]
    [DataRow(100.00, 50.0, 50.00, DisplayName = "50% discount")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "Full discount")]
    [DataRow(79.99, 25.0, 59.9925, DisplayName = "Fractional result")]
    [DataRow(0.00, 50.0, 0.00, DisplayName = "Zero price")]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // ── ApplyDiscount: DynamicData from method ────────────────────────

    public static IEnumerable<object[]> InvalidDiscountData()
    {
        yield return [200.00m, -1.0m];
        yield return [200.00m, 100.01m];
        yield return [200.00m, 150.0m];
    }

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountData), DynamicDataSourceType.Method)]
    [Description("Discount percent outside 0–100 must throw")]
    public void ApplyDiscount_WithInvalidDiscount_ThrowsArgumentOutOfRange(
        decimal price, decimal discountPercent)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent));
    }
}

